    ['To Each His Own Right'] = {
        id = 10,
        start_npc = 'Any Windurst Gate Guard',
        start_zone = 'Heavens Tower',
        start_pos = nil,
        description = 'On the command of Semih Lafihna, captain of the Sibyl Guards, you are requested to track down the Minister of the Orastery, Ajido-Marujido, and discover his true intentions. Inquire at the Orastery if you lose track of him.',
        reward = 'Rank Points\n[Key Item] Starway Stairway bauble',
        fame = nil,
        fame_level = nil,
        title = 'None',
        repeatable = 'No',
        previous = {'The Three Kingdoms'},
        next = {'Written in the Stars'},
        requirements = nil,
        walkthrough = 'Trade enough Crystals (1+) to the Conquest NPC to raise your Rank bar and unlock the Mission, then accept it from the Gate Guard.\n1. Speak to Kupipi in Heavens Tower who will give you the [Key Item] Starway Stairway bauble.\n   - You will be granted access to the upper portion of Heavens Tower. Check the door on the left to go up.\n2. Speak to Rhy Epocan at the top of the Tower for a cutscene.\n   - Use the blue teleporter at the top of the tower to return to the main floor.\n3. Speak to Hakkuru-Rinkuru at the Orastery in Port Windurst (E-7) for hints on Ajido-Marujido\'s whereabouts.\n   - Home Point #1 is closest to Hakkuru-Rinkuru.\n4. Go to Castle Oztroja and fall down the trap door ((I-8) first Map) for a cutscene.\n   - Enter and go to (I-8). There will be two switches (not torches) and a fairly obvious floor panel. One switch will open the door, one will open the floor. Stand in between the two switches and check one. If it opens the door, check the other. They randomly switch, so it will never be the same, day by day.\n   - The person doing the Mission must be the one to pull the lever. Multiple people doing this mission will need to stand back until the trap door closes then individually pull the lever.\n   - In the same room you drop into there is a Blank Target, which is for the Onion Rings quest. You can collect [Key Item] Old ring without having the Quest flagged.\n5. Return to Rhy Epocan to complete the Mission.',
        notes = nil,
    },
    ['Vain'] = {
        id = 20,
        start_npc = 'Any Windurst Gate Guard',
        start_zone = 'Windurst Waters',
        start_pos = 'G-8',
        description = 'At the request of the Aurastery,\nyou are to discover the\nwhereabouts of their former\nminister who fled from his duties\nseveral years ago.',
        reward = 'Rank Points',
        fame = nil,
        fame_level = nil,
        title = 'Fugitive Minister Bounty Hunter',
        repeatable = 'No',
        previous = {'Awakening of the Gods'},
        next = {'The Jester Who\'d Be King'},
        requirements = nil,
        walkthrough = 'Trade enough Crystals to the Conquest NPC to raise your Rank bar and unlock the Mission, then accept it from the Gate Guard.\n1. Talk to Moreno-Toeno in Windurst Waters (L-6) at the Aurastery (northern section, eastern building, HP#2 is closest) for a cutscene and to obtain the [Key Item] "Star Seeker".\n2. Click the Qu\'Hau Spring in Ro\'Maeve (H-6) for a cutscene.\n   - Quick travel options: the Survival Guide to Ro\'Maeve is the fastest way. The Voidwatch warp to Hall of the Gods or Ro\'Maeve are the next best options, respectively.\n3. Go to Davoi and kill Dirtyhanded Gochakzuk NM to obtain a Curse Wand  (). The NM will drop 2 wands per kill, and respawns every 5 minutes.\n   - If you\'re in a party, each player will require one.\n   - The wand won\'t drop if you already have one. Check your storage.\n   - The NM is located on the center island (H-8), so you have to go though Monastic Cavern: Enter Monastic Cavern from entrance 2 at (H-11) in Davoi → Once inside, keep going and take the exit 4 at (I-8) → From here follow the road west around the hill to a wooden elevator, pull the lever to get to the monastery building → Inside, after 2 Oak Doors, the NM will be sitting on a big "throne".\n   - Quick travel options: the Proto-Waypoint to Davoi is the fastest way. Drop into the water, follow the water south-east to (J-10) to get back on land, then hug left until you reach entrance 2. The Survival Guide to Davoi is almost as fast.\n4. Take the elevator back down and walk to the bridge off the center island. Do not drop down in the river or you\'ll have to do the walk of shame back through the cave!\n5. Keep going until you reach Sedal-Godjal at (J-8). Speak to him for a cutscene. He will turn your [Key Item] "Star Seeker" into the [Key Item] Magic-drained "Star Seeker".\n   - You may need to talk multiple times. This can be done before or after obtaining the Curse Wand.\n6. Trade the Curse Wand to Sedal-Godjal for a cutscene.\n   - Optional: Talk to Sedal-Godjal again.\n     - When the refinrocements arrive from San d\'Oria, I\'ll return to Windurst. The professor mustaru have forgotten about Mojiji by now. Huh? He\'s still getting letters. But, I\'m not writing them anymore!\n7. Return to Moreno-Toeno for a cutscene that completes the Mission.\n   - Optional: Talk to Moreno-Toeno again.\n     - In closing, there is the case of Mojiji... With the sudden cessation of Mojiji\'s correspondence, Professor Koru-Moru slid into an unsettling slump. Let me just say that some of us struck on the same solution as sly old Sedal-Godjal...',
        notes = nil,
    },
